mapper.select:
SELECT ,
       u.nickname AS seller_nickname, u.avatar AS seller_avatar, u.credit_score AS seller_credit_score,
       c.name AS category_name,
       (SELECT pi.image_url FROM product_image pi WHERE pi.product_id = p.id AND pi.is_cover = 1 LIMIT 1) AS cover_image
FROM product p
LEFT JOIN `user` u ON p.user_id = u.id
LEFT JOIN category c ON p.category_id = c.id
WHERE p.deleted = 0

    AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))

AND p.category_id = #{categoryId}
AND p.product_status = #{productStatus}
AND p.audit_status = #{auditStatus}
AND p.user_id = #{userId}
AND p.price >= #{minPrice}
AND p.price <= #{maxPrice}
AND p.quality = #{quality}

    ORDER BY p.price ASC
    ORDER BY p.price DESC
    ORDER BY p.view_count DESC
    ORDER BY p.create_time DESC
